BodyContent.ST:
{region 'Defaults and Mode Selection'}
    //Initialise commands as false
    Generator.DQ.xcmd_Start := FALSE;
    Generator.DQ.xcmd_Stop  := FALSE;
    Generator.DQ.xcmd_Reset := FALSE;
    
    //Command handling
    CASE Generator.Mode OF
        GeneratorMode#MANUAL:
            xStartRequestActive := Generator.HMI.xStartRequest;
            xStopRequestActive  := Generator.HMI.xStopRequest;
            xResetRequestActive := Generator.HMI.xResetRequest;
            xControlAllowed     := TRUE;
    
        GeneratorMode#AUTO:
            xStartRequestActive := xAUTO_StartRequest;
            xStopRequestActive  := xAUTO_StopRequest;
            xResetRequestActive := xAUTO_ResetRequest;
            xControlAllowed     := TRUE;
    
        GeneratorMode#EXTERNAL:
            xStartRequestActive := FALSE;
            xStopRequestActive  := FALSE;
            xResetRequestActive := FALSE;
            xControlAllowed     := FALSE;
    END_CASE;
{endregion}

{region 'Edge Detection'}
    //Rising Edge Detection
    rtStartReq(CLK := xStartRequestActive);
    rtStopReq(CLK := xStopRequestActive);
    rtReset(CLK := xResetRequestActive);

    IF Generator.Mode = GeneratorMode#MANUAL THEN
        Generator.HMI.xStartRequest := FALSE;
        Generator.HMI.xStopRequest  := FALSE;
        Generator.HMI.xResetRequest := FALSE;
    END_IF;
{endregion}

{region 'Feedback Evaluation'}
    // Is Controller Available? 
    xIsAvailable    := Generator.DI.xControllerAvailable;
    
    // Breaker Feedback
    xBreakerOpen        := Generator.DI.xBreakerOpened AND NOT Generator.DI.xBreakerClosed;
    xBreakerClosed      := Generator.DI.xBreakerClosed AND NOT Generator.DI.xBreakerOpened;
    xBreakerInvalid     := Generator.DI.xBreakerOpened AND Generator.DI.xBreakerClosed;
    xBreakerCmdFailed   := Generator.DI.xBreakerCmdFailed;

    // Generator running / ready feedback.
    xIsRunning      := Generator.DI.xReadyAndRunning;

    xIsReadyToLoad  := Generator.DI.xReadyAndRunning
                       AND Generator.DI.xControllerAvailable
                       AND NOT Generator.Interlocks.xLoadBlocked;

    xIsOnLoad       := xIsRunning AND xBreakerClosed;
{endregion}

{region 'Permissions'}
    // Is the Generator allowed to Start?
    xCanStart :=        xEnable
                    AND xControlAllowed
                    AND xRemote
                    AND xIsAvailable
                    AND NOT Generator.Interlocks.xStartBlocked
                    AND NOT Generator.Interlocks.xAutoStartBlocked
                    AND NOT Generator.Status.xFault
                    AND NOT xIsRunning;
    // Is the Generator allowed to Stop?
    xCanStop :=         xEnable
                    AND xControlAllowed
                    AND xRemote
                    AND NOT Generator.Interlocks.xStopBlocked
                    AND xIsRunning;
    // Is the Generator allowed to Reset?
    xCanReset :=        xEnable
                    AND xRemote;
{endregion}

//===================================================================
//EXTERNAL:
//    Observe and follow reality.

//MANUAL/AUTO:
//    Control must follow command sequence.
//    Unexpected running/stopping becomes a fault/alarm.
//===================================================================

{region 'FSM Setup'}
    GeneratorCurrentState := Generator.State;
    GeneratorNextState    := GeneratorCurrentState;
{endregion}

{region 'Generator FSM'}
    //is Gnerator Enabled?
    IF NOT xEnable THEN
        GeneratorNextState  := GeneratorState#UNKNOWN;
        xStartPulseActive   := FALSE;
        xStopPulseActive    := FALSE;
        xResetPulseActive   := FALSE;
    //Generator Breaker Feedback Impossible
    ELSIF xBreakerInvalid THEN
        GeneratorNextState              := GeneratorState#FAULT;
        xStartPulseActive               := FALSE;
        xStopPulseActive                := FALSE;
        xResetPulseActive               := FALSE;
        Generator.Status.xFault         := TRUE;
        Generator.Status.xAlarm         := TRUE;
        Generator.Status.xCmdFailed     := TRUE;
    //Generator Breaker Failed to Open
    ELSIF xBreakerCmdFailed THEN
        GeneratorNextState              := GeneratorState#FAULT;
        xStartPulseActive               := FALSE;
        xStopPulseActive                := FALSE;
        xResetPulseActive               := FALSE;
        Generator.Status.xFault         := TRUE;
        Generator.Status.xAlarm         := TRUE;

    ELSE
        CASE GeneratorCurrentState OF

            GeneratorState#UNKNOWN:
            {region 'Unknown Generator State'}

                xStartPulseActive := FALSE;
                xStopPulseActive  := FALSE;
                xResetPulseActive := FALSE;
                
                // Determine Generator State
                IF xIsOnLoad THEN
                    GeneratorNextState := GeneratorState#RUNNING_LOAD;
                ELSIF xIsRunning THEN
                    GeneratorNextState := GeneratorState#RUNNING;
                ELSE
                    GeneratorNextState := GeneratorState#STOPPED;
                END_IF;
            {endregion}

            GeneratorState#STOPPED:
            {region 'Stopped Generator State'}
                //PLC is Stoppped
                xStopPulseActive := FALSE;
            
                CASE Generator.Mode OF
            
                    GeneratorMode#EXTERNAL:
                        // In external mode, state follows feedback from the external controller.
                        IF xIsOnLoad THEN
                            GeneratorNextState := GeneratorState#RUNNING_LOAD;
                        ELSIF xIsRunning THEN
                            GeneratorNextState := GeneratorState#RUNNING;
                        END_IF;
            
                    GeneratorMode#MANUAL,
                    GeneratorMode#AUTO:
                        // In PLC-controlled modes, starting must go through STARTING.
                        IF rtStartReq.Q AND xCanStart THEN
                            GeneratorNextState := GeneratorState#STARTING;
                            xStartPulseActive  := TRUE;
                        ELSIF xIsRunning THEN
                            GeneratorNextState      := GeneratorState#FAULT;
                            Generator.Status.xFault := TRUE;
                            Generator.Status.xAlarm := TRUE;
                        END_IF;
                ELSE
                    GeneratorNextState := GeneratorState#UNKNOWN;
            
                END_CASE;
            {endregion}

            GeneratorState#STARTING:
            {region 'Generator Starting'}

                CASE Generator.Mode OF

                    GeneratorMode#EXTERNAL:
                        // External mode does not own STARTING. Derive actual state.
                        xStartPulseActive := FALSE;

                        IF xIsOnLoad THEN
                            GeneratorNextState := GeneratorState#RUNNING_LOAD;
                        ELSIF xIsRunning THEN
                            GeneratorNextState := GeneratorState#RUNNING;
                        ELSE
                            GeneratorNextState := GeneratorState#STOPPED;
                        END_IF;

                    GeneratorMode#MANUAL,
                    GeneratorMode#AUTO:
                        IF xIsOnLoad THEN
                            GeneratorNextState            := GeneratorState#RUNNING_LOAD;
                            xStartPulseActive             := FALSE;
                            Generator.Status.xStartFailed := FALSE;
                            Generator.Status.xCmdFailed   := FALSE;

                        ELSIF xIsRunning THEN
                            GeneratorNextState            := GeneratorState#RUNNING;
                            xStartPulseActive             := FALSE;
                            Generator.Status.xStartFailed := FALSE;
                            Generator.Status.xCmdFailed   := FALSE;

                        ELSIF tonStartTimeout.Q THEN
                            GeneratorNextState            := GeneratorState#FAULT;
                            xStartPulseActive             := FALSE;
                            Generator.Status.xStartFailed := TRUE;
                            Generator.Status.xCmdFailed   := TRUE;
                            Generator.Status.xFault       := TRUE;
                            Generator.Status.xAlarm       := TRUE;
                        END_IF;
                ELSE
                    GeneratorNextState := GeneratorState#UNKNOWN;
                END_CASE;
            {endregion}

            GeneratorState#RUNNING:
            {region 'Generator Running'}
                // Generator is Running with NO LOAD
                xStartPulseActive := FALSE;

                CASE Generator.Mode OF

                    GeneratorMode#EXTERNAL:
                        IF NOT xIsRunning THEN
                            GeneratorNextState := GeneratorState#STOPPED;
                        ELSIF xIsOnLoad THEN
                            GeneratorNextState := GeneratorState#RUNNING_LOAD;
                        END_IF;

                    GeneratorMode#MANUAL,
                    GeneratorMode#AUTO:
                        IF NOT xIsRunning THEN
                            // Generator stopped without this FB stopping it.
                            GeneratorNextState      := GeneratorState#FAULT;
                            Generator.Status.xFault := TRUE;
                            Generator.Status.xAlarm := TRUE;

                        ELSIF xIsOnLoad THEN
                            GeneratorNextState := GeneratorState#RUNNING_LOAD;

                        ELSIF rtStopReq.Q AND xCanStop THEN
                            GeneratorNextState := GeneratorState#STOPPING;
                            xStopPulseActive   := TRUE;
                        END_IF;
                ELSE
                    GeneratorNextState := GeneratorState#UNKNOWN;
                END_CASE;
            {endregion}

            GeneratorState#RUNNING_LOAD:
            {region 'Generator Running On Load'}
                //Generator is Running on Load - Breaker is Closed
                xStartPulseActive := FALSE;

                CASE Generator.Mode OF

                    GeneratorMode#EXTERNAL:
                        IF NOT xIsRunning THEN
                            GeneratorNextState := GeneratorState#STOPPED;
                        ELSIF NOT xIsOnLoad THEN
                            GeneratorNextState := GeneratorState#RUNNING;
                        END_IF;

                    GeneratorMode#MANUAL,
                    GeneratorMode#AUTO:
                        IF NOT xIsRunning THEN
                            GeneratorNextState      := GeneratorState#FAULT;
                            Generator.Status.xFault := TRUE;
                            Generator.Status.xAlarm := TRUE;

                        ELSIF NOT xIsOnLoad THEN
                            GeneratorNextState := GeneratorState#RUNNING;

                        ELSIF rtStopReq.Q AND xCanStop THEN
                            GeneratorNextState := GeneratorState#STOPPING;
                            xStopPulseActive   := TRUE;
                        END_IF;
                ELSE
                    GeneratorNextState := GeneratorState#UNKNOWN;
                END_CASE;
            {endregion}

            GeneratorState#STOPPING:
            {region 'Generator Stopping'}

                CASE Generator.Mode OF

                    GeneratorMode#EXTERNAL:
                        // External mode does not own STOPPING. Derive actual state.
                        xStopPulseActive := FALSE;

                        IF xIsOnLoad THEN
                            GeneratorNextState := GeneratorState#RUNNING_LOAD;
                        ELSIF xIsRunning THEN
                            GeneratorNextState := GeneratorState#RUNNING;
                        ELSE
                            GeneratorNextState := GeneratorState#STOPPED;
                        END_IF;

                    GeneratorMode#MANUAL,
                    GeneratorMode#AUTO:
                        IF NOT xIsRunning THEN
                            GeneratorNextState           := GeneratorState#STOPPED;
                            xStopPulseActive             := FALSE;
                            Generator.Status.xStopFailed := FALSE;
                            Generator.Status.xCmdFailed  := FALSE;

                        ELSIF tonStopTimeout.Q THEN
                            GeneratorNextState           := GeneratorState#FAULT;
                            xStopPulseActive             := FALSE;
                            Generator.Status.xStopFailed := TRUE;
                            Generator.Status.xCmdFailed  := TRUE;
                            Generator.Status.xFault      := TRUE;
                            Generator.Status.xAlarm      := TRUE;
                        END_IF;
                ELSE
                    GeneratorNextState := GeneratorState#UNKNOWN;
                END_CASE;
            {endregion}

            GeneratorState#FAULT:
            {region 'Generator Fault'}
                //Generator is in Fault - Needs to be Reset
                xStartPulseActive := FALSE;
                xStopPulseActive  := FALSE;

                IF rtReset.Q AND xCanReset THEN
                    Generator.Status.xFault       := FALSE;
                    Generator.Status.xAlarm       := FALSE;
                    Generator.Status.xCmdFailed   := FALSE;
                    Generator.Status.xStartFailed := FALSE;
                    Generator.Status.xStopFailed  := FALSE;
                    GeneratorNextState            := GeneratorState#UNKNOWN;
                    xResetPulseActive             := TRUE;
                END_IF;
            {endregion}

        ELSE
            GeneratorNextState := GeneratorState#UNKNOWN;
        END_CASE;
    END_IF;
{endregion}

{region 'Timer Control'}
    tonStartPulse(
        IN := xStartPulseActive,
        PT := tStartPulse
    );
    tonStopPulse(
        IN := xStopPulseActive,
        PT := tStopPulse
    );
    tonResetPulse(
        IN := xResetPulseActive,
        PT := tResetPulse
    );
    tonStartTimeout(
        IN := GeneratorNextState = GeneratorState#STARTING,
        PT := tStartTimeout
    );
    tonStopTimeout(
        IN := GeneratorNextState = GeneratorState#STOPPING,
        PT := tStopTimeout
    );
{endregion}

{region 'Pulse Control'}
    //Start Pulse Control
    IF tonStartPulse.Q  OR Generator.Interlocks.xStartBlocked
                        OR Generator.Interlocks.xAutoStartBlocked
                        OR NOT xControlAllowed 
    THEN
        xStartPulseActive := FALSE;
    END_IF;

    //Stop Pulse Control
    IF tonStopPulse.Q   OR Generator.Interlocks.xStopBlocked
                        OR NOT xControlAllowed 
    THEN
        xStopPulseActive := FALSE;
    END_IF;

    //Reset Pulse Control
    IF tonResetPulse.Q  OR NOT xControlAllowed THEN
        xResetPulseActive := FALSE;
    END_IF;
{endregion}

{region 'State & Mode Values'}
    //State Control:
    Generator.State := GeneratorNextState;
    //State Values:
    CASE Generator.State OF
        GeneratorState#UNKNOWN:      Generator.iState := 0;
        GeneratorState#STOPPED:      Generator.iState := 1;
        GeneratorState#STOPPING:     Generator.iState := 2;
        GeneratorState#STARTING:     Generator.iState := 3;
        GeneratorState#RUNNING:      Generator.iState := 4;
        GeneratorState#RUNNING_LOAD: Generator.iState := 5;
        GeneratorState#FAULT:        Generator.iState := 6;
    ELSE
        Generator.iState := 0;
    END_CASE;
    //Mode Values:
    CASE Generator.Mode OF
        GeneratorMode#MANUAL:        Generator.iMode := 0;
        GeneratorMode#AUTO:          Generator.iMode := 1;
        GeneratorMode#EXTERNAL:      Generator.iMode := 2;
    ELSE
        Generator.iMode := 0;
    END_CASE;
{endregion}

{region 'Commands'}
    Generator.DQ.xcmd_Start := xStartPulseActive    AND NOT tonStartPulse.Q;
    Generator.DQ.xcmd_Stop  := xStopPulseActive     AND NOT tonStopPulse.Q;
    Generator.DQ.xcmd_Reset := xResetPulseActive    AND NOT tonResetPulse.Q;
{endregion}

{region 'Safety Outputs'}
    Generator.DQ.xAutoStartInhibit := Generator.Interlocks.xAutoStartBlocked;
    Generator.DQ.xLoadInhibit      := Generator.Interlocks.xLoadBlocked;
{endregion}

{region 'Set Statuses'}
    // Available means healthy and usable, not only controller present.
    Generator.Status.xAvailable     :=  xIsAvailable
                                        AND NOT Generator.Status.xFault;

    // Running is physical feedback, so it may stay TRUE even during a fault.
    Generator.Status.xRunning       := xIsRunning;

    // Ready to load means the generator can safely accept load.
    Generator.Status.xReadyToLoad   :=  xIsReadyToLoad
                                        AND NOT Generator.Status.xFault;

    Generator.Status.xRemote        :=  xRemote;

    //Command is Busy
    Generator.Status.xCmdBusy       :=      (GeneratorNextState = GeneratorState#STARTING)
                                        OR  (GeneratorNextState = GeneratorState#STOPPING);
{endregion}
